import React, { useEffect, useState } from 'react';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';

function StatCard({ label, value, color }) {
  return (
    <div style={{ background: '#fff', borderRadius: 16, padding: '24px 28px', boxShadow: '0 2px 12px rgba(0,0,0,0.07)', borderLeft: `5px solid ${color}` }}>
      <p style={{ margin: '0 0 10px', color: '#64748b', fontSize: 14, fontWeight: 500 }}>{label}</p>
      <h3 style={{ margin: 0, fontSize: 30, fontWeight: 800, color: '#1e293b' }}>{value ?? '-'}</h3>
    </div>
  );
}

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axiosInstance.get('/admin/stats').then(r => { setStats(r.data.stats); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <Layout><p style={{ color: '#94a3b8', fontSize: 16 }}>Loading stats...</p></Layout>;
  if (!stats) return <Layout><p style={{ color: '#ef4444', fontSize: 16 }}>Failed to load stats</p></Layout>;

  const sections = [
    { title: 'Customers', color: '#3b82f6', cards: [['Total', stats.customers.total], ['Active', stats.customers.active], ['Pending KYC', stats.customers.pendingKYC], ['AT RISK Accounts', stats.customers.atRisk]] },
    { title: 'Accounts', color: '#8b5cf6', cards: [['Total Accounts', stats.accounts.total], ['Pending Approval', stats.accounts.pending], ['Total Balance', `Rs. ${stats.accounts.totalBalance?.toLocaleString('en-IN')}`]] },
    { title: 'Transactions', color: '#22c55e', cards: [['Total', stats.transactions.total], ['Today Count', stats.transactions.todayCount], ['Deposited Today', `Rs. ${stats.transactions.todayDeposited?.toLocaleString('en-IN')}`], ['Withdrawn Today', `Rs. ${stats.transactions.todayWithdrawn?.toLocaleString('en-IN')}`]] },
    { title: 'Loans', color: '#f59e0b', cards: [['Pending Approval', stats.loans.pending], ['Active Loans', stats.loans.active], ['Total Disbursed', `Rs. ${stats.loans.totalDisbursed?.toLocaleString('en-IN')}`]] },
    { title: 'Investments', color: '#ec4899', cards: [['Active FDs', stats.investments.activeFDs], ['Active RDs', stats.investments.activeRDs]] },
    { title: 'Support', color: '#64748b', cards: [['Open Tickets', stats.support.open], ['In Progress', stats.support.inProgress]] },
  ];

  return (
    <Layout>
      <h2 style={{ margin: '0 0 32px', color: '#1e293b', fontSize: 28, fontWeight: 700 }}>Admin Dashboard</h2>
      {sections.map(sec => (
        <div key={sec.title} style={{ marginBottom: 36 }}>
          <h3 style={{ margin: '0 0 18px', color: '#475569', fontSize: 17, fontWeight: 700 }}>{sec.title}</h3>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: 18 }}>
            {sec.cards.map(([lbl, val]) => <StatCard key={lbl} label={lbl} value={val} color={sec.color} />)}
          </div>
        </div>
      ))}
    </Layout>
  );
}
